import exerciseImageUploadSection from './exerciseImageUploadSection';
export default function normalExerciseModalContent(exercise, loggedInImageUploadSecion) {
    return (
    /* html */
    "<span>\n      ".concat(exerciseImageUploadSection(loggedInImageUploadSecion), "\n      \n      <input value=\"normal\" hidden id=\"exerciseInputsType\">\n\n      <div class=\"flex h-24 mt-6 flex-col\">\n        <div class=\"text-center mr-3 h-full w-full\">\n          <input class=\"rounded-md border border-gray-300 shadow-sm px-4 py-2 bg-white text-base font-medium text-gray-700 focus:outline-none w-full h-12\" id=\"modal-title\" autocomplete=\"off\" value=\"").concat(exercise.name, "\" placeholder=\"Exercise name\" required maxlength=\"100\">\n        </div>\n\n        <div class=\"flex items-center justify-center h-full w-full mt-2 relative select-none bg-white\">\n          <div class=\"flex w-full h-12 text-black bg-white rounded-md border border-gray-300 shadow-sm px-2 py-1.5 edit-exercise-type\">\n            <input \n              type=\"number\" \n              value=\"").concat(exercise.amount, "\" \n              class=\"w-1/3 sm:w-full outline-none p-1\" \n              onchange=\"this.value = this.value < 1 ? 1 : this.value\"\n              required\n              id=\"exercise-amount\"\n            >\n            <select class=\"bg-white w-full outline-none\" onchange=\"UI.updateExerciseModalValues(event)\" id=\"exercise-type\">\n              <option ").concat(exercise.type == 'TIMED' ? 'selected' : '', " value=\"TIMED\">seconds</option>\n              <option ").concat(exercise.type == 'REPS' ? 'selected' : '', " value=\"REPS\">reps</option>\n              <option ").concat(exercise.type == 'TIMED-REPS' ? 'selected' : '', " value=\"TIMED-REPS\">timed reps</option>\n            </select>\n            <div class=\"bg-white h-full w-full flex justify-center sm:block\">\n              <div class=\"timed-reps flex p-1").concat(exercise.type == 'TIMED-REPS' ? '' : ' hidden', "\">\n                <div>per</div>\n                <div class=\"flex mx-2\">\n                  <span id=\"inbetween-span\">").concat(exercise.type == 'TIMED-REPS' ? exercise.inbetween : '5', "</span>\n                  <input hidden value=\"").concat(exercise.type == 'TIMED-REPS' ? exercise.inbetween : '5', "\" id=\"inbetween-input\">\n                </div>\n                <div>secs</div>\n                <div class=\"ml-2 flex flex-col\">\n                  <button type=\"button\" class=\"h-3 w-4 p-0.5 bg-gray-300 outline-none mb-[1px]\" onclick=\"UI.changeInbetween('up')\">\n                    <img src=\"/assets/icons/up.svg\" class=\"h-full w-full\">\n                  </button>\n                  <button type=\"button\" class=\"h-3 w-4 p-0.5 bg-gray-300 outline-none mt-[1px]\" onclick=\"UI.changeInbetween('down')\">\n                    <img src=\"/assets/icons/down.svg\" class=\"h-full w-full\">\n                  </button>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </span>"));
}
